#include <stdio.h>
#include <stdlib.h>
int main(){
  FILE*f=fopen("/app/image.ppm","r");
  if(!f){perror("open");return 1;}
  char magic[8]; int w,h,maxv;
  fscanf(f,"%s %d %d %d",magic,&w,&h,&maxv);
  printf("%s %dx%d max=%d\n",magic,w,h,maxv);
  int n=w*h;
  int*r=malloc(n*sizeof(int)),*g=malloc(n*sizeof(int)),*b=malloc(n*sizeof(int));
  for(int i=0;i<n;i++) fscanf(f,"%d %d %d",&r[i],&g[i],&b[i]);
  // sample corners and center
  int pts[][2]={{0,0},{w-1,0},{0,h-1},{w-1,h-1},{w/2,h/2},{w/2,0},{w/2,h-1},{0,h/2},{w-1,h/2}};
  for(int i=0;i<9;i++){int x=pts[i][0],y=pts[i][1],idx=y*w+x;printf("(%d,%d): %d %d %d\n",x,y,r[idx],g[idx],b[idx]);}
  // unique colors
  int uniq=0; for(int i=0;i<n;i++) if(r[i]==r[0]&&g[i]==g[0]&&b[i]==b[0]) uniq++;
  printf("pixels matching first: %d/%d\n",uniq,n);
  // sample row 0 every 100 px
  printf("row0: "); for(int x=0;x<w;x+=100)printf("(%d,%d,%d)%s",r[x],g[x],b[x],x+100<w?" ":""); printf("\n");
  // sample col 0 every 50 rows
  printf("col0: "); for(int y=0;y<h;y+=50){int idx=y*w;printf("(%d,%d,%d)%s",r[idx],g[idx],b[idx],y+50<h?" ":"");} printf("\n");
  // sample middle row
  printf("row300: "); for(int x=0;x<w;x+=100){int idx=300*w+x;printf("(%d,%d,%d)%s",r[idx],g[idx],b[idx],x+100<w?" ":"");} printf("\n");
  // find where colors change in col w/2
  printf("col400 transitions:\n"); int prev=-1; for(int y=0;y<h;y++){int idx=y*w+400;int c=r[idx]*65536+g[idx]*256+b[idx];if(c!=prev){printf("y=%d: %d %d %d\n",y,r[idx],g[idx],b[idx]);prev=c;}}
  // count unique colors total (sample)
